const teamCoins = (id) => LISTENERS.filter((l) => l.team === id).reduce((s, l) => s + l.coins, 0);
const teamMembers = (id) => LISTENERS.filter((l) => l.team === id);

function assignTeams() {
  const sums = {};
  TEAMS.forEach((t) => (sums[t.id] = teamCoins(t.id)));
  LISTENERS.forEach((l) => {
    if (!l.team) {
      const lightest = TEAMS.reduce((a, b) => (sums[a.id] <= sums[b.id] ? a : b));
      l.team = lightest.id;
      sums[lightest.id] += l.coins;
    }
  });
}
assignTeams();

// チームごとの レベル（コイン → 5だんかい）
// チームの じつりょくに あわせて 目標を かえています
const TEAM_TIERS_BY_ID = {
  omurice:   [0, 45000, 120000, 280000, 350000, 400000, 500000],
  gyoza:     [0, 60000, 120000, 200000, 240000, 270000, 300000],
  chococake: [0, 5000, 10000, 40000, 60000, 80000, 100000],
};
function teamTiers(id) {
  return TEAM_TIERS_BY_ID[id] || [0, 5000, 30000, 100000, 300000];
}
function teamStage(coins, id) {
  const tiers = teamTiers(id);
  let s = 0;
  tiers.forEach((t, i) => { if (coins >= t) s = i; });
  return s;
}

